      AAFactValue value=entry.getValue();
      line[count++]=""+df.format(value.getValue());
      line[count++]=""+df.format(value.getFilteredValue());
      line[count++]=""+df.format(value.getCount());
      if("sum".equalsIgnoreCase(af.getSummaryType())){
        if(value.getCount()==0) line[count++]="0";
        else line[count++]=""+df.format(value.getValue().divide(new BigDecimal(value.getCount()),2, BigDecimal.ROUND_HALF_UP));
      }
      else if("frate".equalsIgnoreCase(af.getSummaryType())){
        if(value.getValue().intValue()==0) line[count++]="0";
        else line[count++]=""+df.format(value.getFilteredValue().multiply(new BigDecimal(100)).divide(value.getValue(), 2, BigDecimal.ROUND_HALF_UP));
      }
